// Pega o body do webhook
const body = $json.body;

// 1️⃣ Bloqueia apenas mensagens enviadas pelo próprio agente
if (body.fromMe === true) {
  return [];
}

// 2️⃣ Identifica tipo da mensagem
let mensagemLead = null;
let tipoMensagem = null;

if (body.text && body.text.message) {
  tipoMensagem = "texto";
  mensagemLead = body.text.message;
} 
else if (body.audio) {
  tipoMensagem = "audio";
  mensagemLead = body.audio;
}
else if (body.image) {
  tipoMensagem = "imagem";
  mensagemLead = body.image;
}
else if (body.document) {
  tipoMensagem = "documento";
  mensagemLead = body.document;
}
else {
  // Se não for nenhum desses, ainda deixa passar
  tipoMensagem = "outro";
  mensagemLead = body;
}

// 3️⃣ Retorna mantendo sua estrutura original
return [
  {
    json: {
      ...$json,
      tipoMensagem,
      mensagemLead,
      telefoneLead: body.phone,
      messageId: body.messageId
    }
  }
];

